const Billing = () => {
  const [usage, setUsage] = useState(null);
  const [plans, setPlans] = useState([]);
  const [referralCode, setReferralCode] = useState('');
  const [feedback, setFeedback] = useState('');
  const [loading, setLoading] = useState(true);

  const loadBillingData = async () => {
    try {
      setLoading(true);
      const [usageRes, plansRes] = await Promise.all([
        axios.get(`${API_BASE_URL}/account/usage`),
        axios.get(`${API_BASE_URL}/plans`),
      ]);
      setUsage(usageRes.data);
      setPlans(plansRes.data || []);
    } catch (error) {
      setFeedback(error.response?.data?.error || 'Ошибка загрузки billing данных');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadBillingData();
  }, []);

  const changePlan = async (planCode) => {
    try {
      const { data } = await axios.patch(`${API_BASE_URL}/account/plan`, { plan: planCode });
      setUsage(data.usage);
      setFeedback(data.message || 'Тариф обновлен');
    } catch (error) {
      setFeedback(error.response?.data?.error || 'Не удалось обновить тариф');
    }
  };

  const applyReferral = async (event) => {
    event.preventDefault();
    if (!referralCode.trim()) return;

    try {
      const { data } = await axios.post(`${API_BASE_URL}/referrals/apply`, {
        referralCode: referralCode.trim(),
      });
      setUsage(data.usage);
      setFeedback(data.message || 'Реферальный код применен');
      setReferralCode('');
    } catch (error) {
      setFeedback(error.response?.data?.error || 'Не удалось применить код');
    }
  };

  return (
    <div className="dashboard">
      <SidebarNav />

      <main className="main-content">
        <div className="integrations-page">
          <h1>Billing и Usage</h1>
          <p>Управляйте тарифом, кредитами и реферальными бонусами.</p>

          {loading ? <p>Загрузка...</p> : (
            <>
              {usage && (
                <div className="integration-card billing-card">
                  <h3>Текущий аккаунт</h3>
                  <p>План: <strong>{String(usage.plan || 'free').toUpperCase()}</strong></p>
                  <p>Кредиты: <strong>{usage.creditsUsed || 0}</strong> / {usage.creditsLimit || 0}</p>
                  <p>Осталось: <strong>{Math.max(0, usage.creditsRemaining || 0)}</strong></p>
                  <p>Ваш рефкод: <strong>{usage.referralCode || '-'}</strong></p>
                  <p>Приглашено: <strong>{usage.referralsCount || 0}</strong></p>
                </div>
              )}

              <div className="integrations-grid">
                {plans.map(plan => (
                  <div className="integration-card" key={plan.code}>
                    <h3>{plan.name}</h3>
                    <p>{plan.monthlyPrice === null ? 'Custom' : `$${plan.monthlyPrice}/mo`}</p>
                    <p>Лимит: {plan.creditsLimit} кредитов</p>
                    <button className="btn-secondary" onClick={() => changePlan(plan.code)}>
                      Выбрать {plan.name}
                    </button>
                  </div>
                ))}
              </div>

              <form onSubmit={applyReferral} className="generator-form" style={{ marginTop: '1rem' }}>
                <div className="form-group">
                  <label>Применить реферальный код</label>
                  <input
                    type="text"
                    value={referralCode}
                    onChange={(e) => setReferralCode(e.target.value)}
                    placeholder="Введите код, например ref_ab12cd34"
                  />
                </div>
                <button type="submit" className="btn-primary">Применить код</button>
              </form>

              {feedback && <div className="error" style={{ marginTop: '1rem' }}>{feedback}</div>}
            </>
          )}
        </div>
      </main>
    </div>
  );
};

// App Router
const App = () => (
  <BrowserRouter>
    <Routes>
      <Route path="/" element={<Landing />} />
      <Route path="/login" element={<Login />} />
      <Route path="/register" element={<Register />} />
      <Route path="/dashboard" element={<Dashboard />} />
      <Route path="/generator" element={<Generator />} />
      <Route path="/project/:id" element={<ProjectDetail />} />
      <Route path="/learning" element={<Learning />} />
      <Route path="/billing" element={<Billing />} />
      <Route path="/integrations" element={<Integrations />} />
    </Routes>
  </BrowserRouter>
);

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<App />);
